clear(); close all;
%[text] ## Parameters
wavelen = 1;              % normalized wavelength
elemSpace = wavelen / 2;  % half-wavelength spacing
size = [4 4];             % number of array elements
numSnap = 2000;           % number of signal snapshots
snr_db = 10;              % signal-to-noise ratio in dB
pwrSource = 1;            % source signal power
pwrNoise = pwrSource / (10^(snr_db / 10)); % noise power from SNR
E = wgs84Ellipsoid('meters');
numSource = 3;            % number of signal sources

% Positions
lat = [30   30   24   31   28];
lon = [120  128  136  123  134];
h   = [0    0    0    550e3 550e3];
[x, y, z] = geodetic2ecef(E, lat, lon, h);

posUsr1 = [x(1); y(1); z(1)];
posUsr2 = [x(2); y(2); z(2)];
posUsr3 = [x(3); y(3); z(3)];
posSat1 = [x(4); y(4); z(4)];
posSat2 = [x(5); y(5); z(5)];

% direction vector
rotMat1_l2g = get_rotation_mat(-posSat1);
rotMat2_l2g = get_rotation_mat(-posSat2);

doa1_local = globalToLocalDoa([posUsr1, posUsr2, posUsr3], posSat1, rotMat1_l2g) %[output:1a355339]
doa2_local = globalToLocalDoa([posUsr1, posUsr2, posUsr3], posSat2, rotMat2_l2g) %[output:50ba1893]

% design a URA with m elements
arrUpa = createUpa(size, elemSpace);
arrUra = ura_2d(size, elemSpace);
%%
%[text] ## DOA estimation
% Stochastic signal model
[~, R1, ~] = snapGenStochastic(arrUpa, doa1_local, wavelen, numSnap, pwrNoise, pwrSource);
[~, R2, ~] = snapGenStochastic(arrUpa, doa2_local, wavelen, numSnap, pwrNoise, pwrSource);

doaGrid1 = genDoaGrid("latlon", 2, [50 50], [min(lat)-5, max(lat)+5; min(lon)-5, max(lon)+5], "ecef", [], posSat1, [], E);
doaGrid2 = genDoaGrid("latlon", 2, [50 50], [min(lat)-5, max(lat)+5; min(lon)-5, max(lon)+5], "ecef", [], posSat2, [], E);

spMusic1 = estimatorMusic(arrUpa, wavelen, R1, numSource, doaGrid1, true);
spMusic2 = estimatorMusic(arrUpa, wavelen, R2, numSource, doaGrid2, true);
spMusicJoint = estimatorMusic({arrUpa, arrUpa}, wavelen, {R1, R2}, numSource, {doaGrid1, doaGrid2}, true);

spMvdr1 = estimatorMvdr(arrUpa, wavelen, R1, numSource, doaGrid1, true);
spMvdr2 = estimatorMvdr(arrUpa, wavelen, R2, numSource, doaGrid2, true);
spMvdrJoint = estimatorMvdr({arrUpa, arrUpa}, wavelen, {R1, R2}, numSource, {doaGrid1, doaGrid2}, true);

spMle1 = estimatorMleStoConOpt(arrUpa, wavelen, R1, numSource, doaGrid1);
spMle2 = estimatorMleStoConOpt(arrUpa, wavelen, R2, numSource, doaGrid2);
spMleJoint = estimatorMleStoConOpt({arrUpa, arrUpa}, wavelen, {R1, R2}, numSource, {doaGrid1, doaGrid2});

sp1_music = music_2d(R1, numSource, arrUra, wavelen, [180 45], 'RefineEstimates', true);
sp2_music = music_2d(R2, numSource, arrUra, wavelen, [180 45], 'RefineEstimates', true);

spMusic1.latlonEst %[output:8b2552c0]
spMusic2.latlonEst %[output:52eb4e68]
spMusicJoint.latlonEst %[output:5a9de6ab]
% doa1_local_est = sp1_music.x_est
% doa2_local_est = sp2_music.x_est
%%
figure(1) %[output:8eafa092]
subplot(131) %[output:8eafa092]
mesh(spMusic1.plot.x, spMusic1.plot.y, spMusic1.plot.z) %[output:8eafa092]
subplot(132) %[output:8eafa092]
mesh(spMusic2.plot.x, spMusic2.plot.y, spMusic2.plot.z) %[output:8eafa092]
subplot(133) %[output:8eafa092]
mesh(spMusicJoint.plot.x, spMusicJoint.plot.y, spMusicJoint.plot.z) %[output:8eafa092]
figure(2) %[output:256039e2]
subplot(131) %[output:256039e2]
mesh(spMvdr1.plot.x, spMvdr1.plot.y, spMvdr1.plot.z) %[output:256039e2]
subplot(132) %[output:256039e2]
mesh(spMvdr2.plot.x, spMvdr2.plot.y, spMvdr2.plot.z) %[output:256039e2]
subplot(133) %[output:256039e2]
mesh(spMvdrJoint.plot.x, spMvdrJoint.plot.y, spMvdrJoint.plot.z) %[output:256039e2]

